const item = items[0].json;

const required = ['name', 'audience_segment', 'start_date', 'end_date', 'budget_usd'];
for (const field of required) {
  if (item[field] === undefined || item[field] === null || item[field] === '') {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Parse numeric fields and JSON strings where relevant
const budget = Number(item.budget_usd);
if (Number.isNaN(budget) || budget <= 0) {
  throw new Error('budget_usd must be a positive number');
}

let channels = {};
let goals = {};
try {
  channels = item.channels ? JSON.parse(item.channels) : {};
} catch (e) {
  throw new Error('channels must be valid JSON');
}

try {
  goals = item.goals ? JSON.parse(item.goals) : {};
} catch (e) {
  throw new Error('goals must be valid JSON');
}

return [{
  json: {
    ...item,
    budget_usd: budget,
    channels,
    goals,
  },
}];

const campaign = { ...items[0].json };

if (!campaign.channels?.email) {
  return [{ json: { ...campaign, email: { enabled: false } } }];
}

const email = {
  enabled: true,
  segmentId: 'seg_placeholder',
  campaignId: 'cmp_email_placeholder',
  status: 'draft'
};

return [{ json: { ...campaign, email } }];

const campaign = { ...items[0].json };

if (!campaign.channels?.ads) {
  return [{ json: { ...campaign, ads: { enabled: false } } }];
}

const ads = {
  enabled: true,
  metaAdSetId: 'adset_meta_placeholder',
  googleCampaignId: 'gads_placeholder',
  budget_usd: campaign.budget_usd
};

return [{ json: { ...campaign, ads } }];

const campaign = { ...items[0].json };

if (!campaign.channels?.crm) {
  return [{ json: { ...campaign, crm: { enabled: false } } }];
}

const crm = {
  enabled: true,
  campaignId: 'crm_campaign_placeholder',
  taggedAccounts: 120
};

return [{ json: { ...campaign, crm } }];

const campaign = { ...items[0].json };

if (!campaign.channels?.internal_comms) {
  return [{ json: { ...campaign, internalComms: { enabled: false } } }];
}

const internalComms = {
  enabled: true,
  slackChannel: '#campaigns',
  messageLink: 'https://your-workspace.slack.com/archives/campaign_message_placeholder'
};

return [{ json: { ...campaign, internalComms } }];

const c = items[0].json;

const lines = [];
lines.push(`# Campaign: ${c.name}`);
lines.push('');
lines.push(`Audience: ${c.audience_segment}`);
lines.push(`Dates: ${c.start_date} → ${c.end_date}`);
lines.push(`Budget: $${c.budget_usd}`);
lines.push('');
lines.push('## Channels');

if (c.email?.enabled) {
  lines.push('- Email: draft campaign created (segment: segment placeholder, ID: cmp_email_placeholder)');
} else {
  lines.push('- Email: disabled');
}

if (c.ads?.enabled) {
  lines.push('- Ads: Meta and Google campaigns created (IDs: placeholders)');
} else {
  lines.push('- Ads: disabled');
}

if (c.crm?.enabled) {
  lines.push('- CRM: campaign record created and accounts tagged');
} else {
  lines.push('- CRM: disabled');
}

if (c.internalComms?.enabled) {
  lines.push('- Internal comms: posted to #campaigns');
} else {
  lines.push('- Internal comms: disabled');
}

const summary_markdown = lines.join('
');

return [{ json: { ...c, summary_markdown } }];
